  3	import { useDispatch, useSelector } from 'react-redux';
  4	import { BlueInfoCircleIcon } from '@openshift-console/dynamic-plugin-sdk';
  5	import { CodeEditor, Language } from '@patternfly/react-code-editor';
  6	import {
  7	  ActionGroup,
  8	  Button,
  9	  CodeBlock,
 10	  CodeBlockAction,
 11	  CodeBlockCode,
 12	  Form,
 13	  Split,
 14	  SplitItem,
 15	  Text,
 16	  TextVariants,
 17	} from '@patternfly/react-core';
 18	import { PencilAltIcon, UndoIcon } from '@patternfly/react-icons';
 19	
 20	import { AttachmentTypes, isAttachmentChanged } from '../attachments';
 21	import { useBoolean } from '../hooks/useBoolean';
 22	import { attachmentSet, openAttachmentClear, openAttachmentSet } from '../redux-actions';
 23	import { State } from '../redux-reducers';
 24	import { Attachment } from '../types';
 25	import CopyAction from './CopyAction';
 26	import Modal from './Modal';
 27	import ResourceIcon from './ResourceIcon';
 28	
 29	const ResourceHeader: React.FC = () => {
 30	  const attachment: Attachment = useSelector((s: State) => s.plugins?.ols?.get('openAttachment'));
 31	
 32	  return (
 33	    <Text className="ols-plugin__code-block__title" component={TextVariants.h5}>
 34	      <ResourceIcon kind={attachment?.kind} /> {attachment?.name}
 35	      {isAttachmentChanged(attachment) && (
 36	        <span className="ols-plugin__inline-icon">
 37	          <PencilAltIcon />
 38	        </span>
 39	      )}
 40	    </Text>
 41	  );
 42	};
 43	
 44	type EditorProps = {
 45	  onChange: (v: string) => void;
 46	};
 47	
 48	const Editor: React.FC<EditorProps> = ({ onChange }) => {
 49	  const attachment: Attachment = useSelector((s: State) => s.plugins?.ols?.get('openAttachment'));
 50	
 51	  const onEditorDidMount = (_editor, monaco) => {
 52	    // Work around crash when CodeEditor attempts to call this nonexistent function
 53	    // TODO: Figure out why this is happening
 54	    monaco.editor.onDidChangeMarkers = () => {};
 55	  };
 56	
 57	  // In more recent versions of the dynamic plugin SDK, the useUserSettings hook can be used to get
 58	  // the current theme, but to maintain 4.15 compatibility we are not upgrading the SDK yet
 59	  const isDarkTheme = document.documentElement.classList.contains('pf-v6-theme-dark');
 60	
 61	  return (
 62	    <CodeEditor
 63	      code={attachment?.value}
 64	      customControls={<ResourceHeader />}
 65	      height="calc(24rem - 52px)"
 66	      isDarkTheme={isDarkTheme}
 67	      isLanguageLabelVisible
 68	      isMinimapVisible
 69	      language={
 70	        attachment?.attachmentType === AttachmentTypes.Log ? Language.plaintext : Language.yaml
 71	      }
 72	      onChange={onChange}
 73	      onEditorDidMount={onEditorDidMount}
 74	    />
 75	  );
 76	};
 77	
 78	const Viewer: React.FC = () => {
 79	  const attachment: Attachment = useSelector((s: State) => s.plugins?.ols?.get('openAttachment'));
 80	
 81	  return (
 82	    <CodeBlock
 83	      actions={
 84	        <>
 85	          <CodeBlockAction>
 86	            <ResourceHeader />
 87	          </CodeBlockAction>
 88	          <CodeBlockAction>
 89	            <CopyAction value={attachment?.value} />
 90	          </CodeBlockAction>
 91	        </>
 92	      }
 93	      className="ols-plugin__code-block ols-plugin__code-block--attachment"
 94	    >
 95	      <CodeBlockCode
 96	        className="ols-plugin__code-block-code"
 97	        style={
 98	          attachment?.attachmentType === AttachmentTypes.Log ? { whiteSpace: 'pre' } : undefined
 99	        }
100	      >
101	        {attachment?.value}
102	      </CodeBlockCode>
103	    </CodeBlock>
104	  );
105	};
106	
107	const AttachmentModal: React.FC = () => {
108	  const { t } = useTranslation('plugin__lightspeed-console-plugin');
109	
110	  const dispatch = useDispatch();
111	
112	  const attachment: Attachment = useSelector((s: State) => s.plugins?.ols?.get('openAttachment'));
113	
114	  const [isEditing, , setEditing, setNotEditing] = useBoolean(false);
115	  const [editorValue, setEditorValue] = React.useState<string>();
116	
117	  const onClose = React.useCallback(() => {
118	    dispatch(openAttachmentClear());
119	  }, [dispatch]);
120	
121	  const onSave = React.useCallback(() => {
122	    const originalValue =
123	      attachment.originalValue === undefined ? attachment.value : attachment.originalValue;
124	    dispatch(
125	      attachmentSet(
126	        attachment.attachmentType,
127	        attachment.kind,
128	        attachment.name,
129	        attachment.ownerName,
130	        attachment.namespace,
131	        editorValue,
132	        originalValue,
133	      ),
134	    );
135	    dispatch(openAttachmentClear());
136	    setNotEditing();
137	  }, [attachment, dispatch, editorValue, setNotEditing]);
138	
139	  const onRevert = React.useCallback(() => {
140	    const value = attachment.originalValue;
141	    dispatch(openAttachmentSet(Object.assign({}, attachment, { value })));
142	    dispatch(
143	      attachmentSet(
144	        attachment.attachmentType,
145	        attachment.kind,
146	        attachment.name,
147	        attachment.ownerName,
148	        attachment.namespace,
149	        value,
150	        undefined,
151	      ),
152	    );
153	    setEditorValue(value);
154	  }, [attachment, dispatch]);
155	
156	  return (
157	    <Modal
158	      className="ols-plugin__attachment-modal"
159	      isOpen={!!attachment}
160	      onClose={onClose}
161	      title={
162	        <>
163	          <BlueInfoCircleIcon /> {t('Preview attachment')}
164	        </>
165	      }
166	    >
167	      <p>
168	        {t(
169	          'You can preview and optionally edit the code displayed in the modal before attaching it to your prompt.',
170	        )}
171	      </p>
172	      {isEditing ? <Editor onChange={setEditorValue} /> : <Viewer />}
173	      <div className="ols-plugin__attachment-modal-actions">
174	        <Form>
175	          {isEditing ? (
176	            <ActionGroup>
177	              <Button onClick={onSave} type="submit" variant="primary">
178	                {t('Save')}
179	              </Button>
180	              <Button onClick={setNotEditing} variant="link">
181	                {t('Cancel')}
182	              </Button>
183	            </ActionGroup>
184	          ) : (
185	            <Split>
186	              <SplitItem isFilled>
187	                <ActionGroup>
188	                  {attachment?.isEditable && (
189	                    <Button onClick={setEditing} type="submit" variant="primary">
190	                      {t('Edit')}
191	                    </Button>
192	                  )}
193	                  <Button onClick={onClose} variant="link">
194	                    {t('Dismiss')}
195	                  </Button>
196	                </ActionGroup>
197	              </SplitItem>
198	              {attachment?.originalValue && attachment.originalValue !== attachment.value && (
199	                <SplitItem>
200	                  <ActionGroup>
201	                    <Button icon={<UndoIcon />} isDanger onClick={onRevert} variant="link">
202	                      {t('Revert to original')}
203	                    </Button>
204	                  </ActionGroup>
205	                </SplitItem>
206	              )}
207	            </Split>
208	          )}
209	        </Form>
210	      </div>
211	    </Modal>
212	  );
213	};
214	
215	export default AttachmentModal;

